  ('locality-6f0ba476-moex-00549', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '關於個人所得稅制之敘述，下列何者錯誤？', '["允許免稅額的所得稅制，若採單一邊際稅率，平均稅率不會隨所得增加而改變", "單一邊際稅率下，免稅額愈高，稅制的累進性愈高", "列舉扣除可以降低納稅人扣除項目支出的成本", "允許免稅額的作用之一，是會減少課稅的執行成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
