  ('locality-6f0ba476-moex-00551', 'locality-6f0ba476', 'locality-6f0ba476-moex-110-3e700a6a', 'sub-locality-6f0ba476-05', NULL, 'single_choice', '依我國相關法令規定，下列敘述何者錯誤？', '["境外營利事業在我國境內有專為採購貨品用之倉棧，且未用以加工製造貨物，應視為在我國無 固定營業場所", "我國營利事業之國外分公司之營利所得，應待分公司進行盈餘分配後，總公司才應將該筆盈餘 納入所得中繳納我國之所得稅", "我國營利事業之境外所得，若符合租稅協定中有關視同已納稅額扣抵（taxsparing）之規定，則 可將其在所得來源國未繳之稅額，自我國應納稅額中扣抵", "總機構在境外但在境內有固定營業場所之營利事業，應以結算申報方式報繳所得稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:05+00:00", "source_pdf_sha1": "2255401c3abb", "answer_pdf_sha1": "d17af0bc0582", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "312", "s": "1404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
